    /// <term>params.marginMode</term>
    /// <description>
    /// string : 'cross' or 'isolated', default is 'isolated'
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.hedged</term>
    /// <description>
    /// bool : *swap and future only* true for hedged mode, false for one way mode, default is false
